noncompliant:
// Noncompliant: RSA key too small (1024 bits)
using (var rsa = new RSACryptoServiceProvider(1024))
{
    // Weak encryption
}

// Noncompliant: DES uses weak 56-bit key
using (var des = new DESCryptoServiceProvider())
{
    var encryptor = des.CreateEncryptor();
}

// Noncompliant: AES with weak 128-bit key for sensitive data
using (var aes = new AesCryptoServiceProvider())
{
    aes.KeySize = 128; // Weak for highly sensitive data
}

compliant:
// Compliant: RSA with 2048-bit or larger key
using (var rsa = new RSACryptoServiceProvider(2048))
{
    // Strong encryption
}

// Compliant: AES with 256-bit key
using (var aes = new AesCryptoServiceProvider())
{
    aes.KeySize = 256;
    var encryptor = aes.CreateEncryptor();
}

// Compliant: Using modern algorithms with strong keys
using (var rsa = RSA.Create(4096))
{
    // Very strong encryption
}
